var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......으음.","JPN":"……う～ん。","ENG":"Erm...","TWN":"……嗚。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 정신이 드세요 경정님?","JPN":"警視様、気がつきましたか？","ENG":"Ah, you're awake, Major.","TWN":"啊，妳清醒了嗎，警正大人？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"난...... 이게 어떻게 된 거지?","JPN":"私は……いったい何があったの？","ENG":"What... What happened?","TWN":"我……怎麼了？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"휴, 상처가 심해서 걱정했는데 정신이 드셔서 다행이에요.","JPN":"ふう、怪我がひどくて心配したんですが、目が覚めてよかったです。","ENG":"Phew, you were seriously injured. I'm glad you came to.","TWN":"呼，我還擔心妳傷得很嚴重呢，妳清醒過來真是太好了。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......경위? 당신이 그것들을 다 해치운 거야?","JPN":"……マエカワ警部補？　あなたがあいつらを一掃したの？","ENG":"Lieutenant? Did you take them all down?","TWN":"……警衛？那些人都是妳解決的嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아하하, 그럴 리가요. 저 같은 무능력자가 무슨 수로요.","JPN":"あはは、まさか。\\n私のような無能力者にそんなことできるわけないでしょう？","ENG":"Ah hah hah, I wish I did. How could an incompetent like myself do something so amazing?","TWN":"啊哈哈，怎麼可能，像我這種無能力者怎麼做得到。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그러면 어떻게......?","JPN":"じゃあ、どうやって……","ENG":"Then what happened?","TWN":"那是怎麼……？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아무래도 마젤란 예언회가 그 여학생을 노리고 있는 것 같아서 말이죠.","JPN":"どうもマジェラン預言会があの女子生徒を狙っているような気がしたので。","ENG":"I figured the Magellan's Prediction Society was coming after that student.","TWN":"麥哲倫預言會的目標似乎是那個女學生呢。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님을 쫓아오면서 블랙타이드에 협조 요청을 했어요.","JPN":"警視様を追いかけながら、ブラックタイドに協力を要請しました。","ENG":"So I called the Black Tide on the way to you.","TWN":"我在追警正大人的時候，一邊向黑潮發出了協助請求。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"블랙타이드라면...... 유명한 용병 회사잖아?","JPN":"ブラックタイドって……あの有名な傭兵会社？","ENG":"The Black Tide? Isn't that a famous mercenary company?","TWN":"黑潮……不是那個有名的傭兵公司嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그런 곳을 어떻게......?","JPN":"そんな所にどうやって……","ENG":"I didn't know you had connections in these kind of businesses.","TWN":"妳怎麼知道那種地方……？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"블랙타이드에는 전직 경찰특공대 출신 분들이 많으시거든요.","JPN":"ブラックタイドには、元警察特攻隊の方々が多くいらっしゃいます。","ENG":"There are a lot of former SWAT members working in the Black Tide.","TWN":"黑潮裡有很多人是原警察特攻隊出身的。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래서 저희 요청엔 보수와 상관없이 도움을 주고 계세요.","JPN":"なので私たちが要請すれば、報酬に関わらず力を貸してくださるんです。","ENG":"They help us at our request, regardless of the pay.","TWN":"所以對於我們的請求，無論報酬如何，他們都會予以協助。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"뭐, 무료 봉사기관은 아닌지라 기름값 정도는 제가 따로 대드려야 했지만......","JPN":"まあ、ボランティア団体ではないので、\\nガソリン代くらいは私がお渡ししたんですが……","ENG":"They don't exactly work for free, so I had to pay for gas, but...","TWN":"不過，畢竟他們不是慈善機構，所以油錢還是得分別給一下……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아무튼 정말 위험했어요. 아슬아슬했다니까요?","JPN":"とにかく、本当に危なかったです。ギリギリでしたから！","ENG":"It was dangerous, you know. It was very, very close.","TWN":"總之，真是危險啊。差點就出事了呢。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 그리고 이거......","JPN":"ああ、それからこれ……","ENG":"Oh, right. I believe this is yours.","TWN":"啊，這個……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그, 그거! 이리 줘!","JPN":"そ、それ！　返して！","ENG":"Th-that! Give it to me!","TWN":"那、那個！把那個給我！"},"stage":{"bg":"POLICE_01","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};